function normalizeTasks(data) {
  if (!data) return [];
  if (Array.isArray(data)) return data.filter(Boolean);
  return Object.entries(data).map(([id, task]) => ({ ...(task || {}), id: (task && task.id) ? task.id : id }));
}

function isEmailTask(task) {
  if (!task || typeof task !== 'object') return false;
  return task.source === 'email' || !!task.requester || !!task.requesterEmail;
}

function extractEmail(task) {
  const direct = String(task.requesterEmail || '').trim();
  if (direct) return direct;

  const fromRequester = String(task.requester || '').match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  if (fromRequester) return fromRequester[0];

  const fromDescription = String(task.description || '').match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  if (fromDescription) return fromDescription[0];

  return '';
}

const tasksRaw = $node['Get Tasks'].json || {};
const prevSnapshot = $node['Get Status Snapshot'].json || {};
const tasks = normalizeTasks(tasksRaw);

const currentSnapshot = {};
const changes = [];

for (const task of tasks) {
  if (!isEmailTask(task)) continue;

  const id = String(task.id || '');
  if (!id) continue;

  const status = String(task.status || 'todo');
  const requesterEmail = extractEmail(task);
  const requester = String(task.requester || '').trim();
  const title = String(task.title || 'Task');

  currentSnapshot[id] = {
    status,
    requesterEmail,
    requester,
    title
  };

  const prev = prevSnapshot[id];
  if (!prev) continue;

  const prevStatus = String(prev.status || 'todo');
  if (prevStatus !== status && requesterEmail) {
    changes.push({
      taskId: id,
      title,
      requester,
      requesterEmail,
      oldStatus: prevStatus,
      newStatus: status,
      changedAt: new Date().toISOString()
    });
  }
}

return [{
  json: {
    changedCount: changes.length,
    changes,
    currentSnapshot
  }
}];

function label(status) {
  const s = String(status || '').toLowerCase();
  if (s === 'triage') return 'Triage';
  if (s === 'todo') return 'To Do';
  if (s === 'progress') return 'In Progress';
  if (s === 'feedback') return 'Await Feedback';
  if (s === 'done') return 'Done';
  return status || 'Unknown';
}

const taskTitle = String($json.title || 'Task').trim();
const fromStatus = label($json.oldStatus || 'todo');
const toStatus = label($json.newStatus || 'todo');
const requester = String($json.requester || '').trim();

const greeting = requester ? `Hallo ${requester},` : 'Hallo,';
const subject = `Join Update: ${taskTitle} -> ${toStatus}`;
const body =
  `${greeting}\n\n` +
  `dein Request hat ein Status-Update erhalten.\n\n` +
  `Task: ${taskTitle}\n` +
  `Vorher: ${fromStatus}\n` +
  `Jetzt: ${toStatus}\n\n` +
  `Wenn du Rueckfragen hast, antworte direkt auf diese E-Mail.\n\n` +
  `Viele Gruesse\n` +
  `Join Team`;

return [{
  json: {
    to: String($json.requesterEmail || '').trim(),
    subject,
    body
  }
}];
